// Build Context + Prompt — join worldcup26.ir feeds, convert kickoffs (US venue time) to Bangladesh time, build a COMPACT MOBILE-FIRST next-day prompt.
// Suffix-proof: auto-resolves duplicated node names (Get Teams, Get Teams1, Get Teams2 ...).
function pickNode(base){
  for (let s = 0; s <= 5; s++){
    const nm = s === 0 ? base : base + s;
    let raw;
    try { raw = $(nm).all(); } catch (e) { continue; }
    if (raw && raw.length) return raw.map(i => i.json);
  }
  throw new Error('No executed node found for "' + base + '". Run the FULL workflow from the trigger (Test workflow), not a single step.');
}
function unwrap(items){
  if (items.length === 1){
    const j = items[0] || {};
    if (Array.isArray(j)) return j;
    for (const k of ['data','teams','games','groups','stadiums','result','results']){
      if (Array.isArray(j[k])) return j[k];
    }
  }
  return items;
}

let dWrap;
for (let s = 0; s <= 5; s++){
  const nm = s === 0 ? 'Set Date (BD)' : 'Set Date (BD)' + s;
  try { const v = $(nm).first(); if (v){ dWrap = v.json; break; } } catch (e) {}
}
if (!dWrap) throw new Error('Set Date (BD) node not found/executed. Run the full workflow from the trigger.');
const yest = dWrap.yesterday;
const schedDate = dWrap.tomorrow;        // preview the NEXT day
const schedHuman = dWrap.tomorrowHuman;

const teams = unwrap(pickNode('Get Teams'));
const games = unwrap(pickNode('Get Games'));
const groups = unwrap(pickNode('Get Groups'));
const stadiums = unwrap(pickNode('Get Stadiums'));

const teamMap = {};
for (const t of teams){ teamMap[String(t.id)] = t; }
const stadMap = {};
for (const s of stadiums){ stadMap[String(s.id)] = s; }

function teamName(id){ const t = teamMap[String(id)]; return t ? (t.name_en || t.name || ('Team '+id)) : ('Team '+id); }
function teamCode(id){ return (teamMap[String(id)] || {}).fifa_code; }

// Host-city -> IANA timezone (16 WC2026 venues across USA / Mexico / Canada)
function tzForCity(city){
  const c = String(city||'').toLowerCase();
  if (/inglewood|los angeles|santa clara|san francisco|bay area|seattle/.test(c)) return 'America/Los_Angeles';
  if (/arlington|dallas|houston|kansas/.test(c)) return 'America/Chicago';
  if (/atlanta|foxborough|boston|miami|rutherford|new jersey|new york|philadelphia|toronto/.test(c)) return 'America/New_York';
  if (/monterrey/.test(c)) return 'America/Monterrey';
  if (/guadalajara|mexico/.test(c)) return 'America/Mexico_City';
  if (/vancouver/.test(c)) return 'America/Vancouver';
  return 'America/New_York';
}

const enriched = games.map(g => {
  const st = stadMap[String(g.stadium_id)] || {};
  const city = st.city_en || st.city || '';
  const tz = tzForCity(city);
  const dt = DateTime.fromFormat(String(g.local_date || ''), 'MM/dd/yyyy HH:mm', { zone: tz });
  const bd = dt.isValid ? dt.setZone('Asia/Dhaka') : null;
  return {
    id: g.id,
    home: g.home_team_name_en || teamName(g.home_team_id),
    away: g.away_team_name_en || teamName(g.away_team_id),
    home_code: teamCode(g.home_team_id),
    away_code: teamCode(g.away_team_id),
    group: g.group,
    stage: g.type,
    venue: st.name_en || ('Stadium ' + g.stadium_id),
    city: city,
    bd_time: bd ? bd.toFormat('h:mm a') : null,
    kickoff_bd: bd ? (bd.toFormat('ccc dd LLL, h:mm a') + ' BDT') : null,
    kickoff_us_local: dt.isValid ? dt.toFormat('ccc h:mm a ZZZZ') : g.local_date,
    kickoff_bd_date: bd ? bd.toFormat('yyyy-LL-dd') : null,
    finished: String(g.finished).toUpperCase() === 'TRUE',
    score: (g.home_score != null && g.away_score != null) ? (g.home_score + '-' + g.away_score) : null
  };
});

const matches = enriched.filter(g => g.kickoff_bd_date === schedDate);
const recentResults = enriched.filter(g => g.kickoff_bd_date === yest && g.finished);
const upcomingMatches = enriched
  .filter(g => g.kickoff_bd_date && g.kickoff_bd_date > schedDate && !g.finished)
  .sort((a,b) => (a.kickoff_bd_date + a.bd_time).localeCompare(b.kickoff_bd_date + b.bd_time))
  .slice(0, 8);

const standings = groups.map(gr => {
  const rows = (gr.teams || gr.table || []).map(t => {
    const gf = Number(t.gf), ga = Number(t.ga);
    return {
      team: teamName(t.team_id || t.id),
      P: t.mp, W: t.w, D: t.d, L: t.l,
      GD: (Number.isFinite(gf) && Number.isFinite(ga)) ? (gf - ga) : t.gd,
      Pts: t.pts != null ? t.pts : t.points
    };
  }).sort((a,b) => {
    const pa = Number(a.Pts)||0, pb = Number(b.Pts)||0; if (pb !== pa) return pb - pa;
    return (Number(b.GD)||0) - (Number(a.GD)||0);
  });
  return { group: gr.name, table: rows };
});

const context = { scheduleDate: schedDate, scheduleHuman: schedHuman, matchCount: matches.length, timezone: 'Asia/Dhaka', matches, recentResults, upcomingMatches, standings };

const prompt = [
  'You are a professional football analyst producing a COMPACT, MOBILE-FIRST daily FIFA World Cup 2026 briefing for Slack.',
  'The reader is in Bangladesh (Asia/Dhaka, UTC+6); the tournament is hosted in the USA, Canada and Mexico. This briefing PREVIEWS the schedule for ' + schedHuman + ' (' + schedDate + ').',
  '',
  'CORRECTNESS: the DATA block is LIVE official data (schedule, teams, standings, venues, scores) — treat it as GROUND TRUTH, never contradict or invent it. bd_time, kickoff_bd and kickoff_us_local are pre-computed — use them verbatim. Squads, player clubs and win probabilities are YOUR analysis (label win % as estimates); only name players/clubs you are confident about for the 2025/26 season.',
  '',
  'MOBILE FORMAT (CRITICAL): most readers use Slack on a PHONE. Do NOT use triple-backtick code blocks, tables, or pipe (|) alignment — they get cut off and wrap badly on small screens. Use ONLY short bullet lines. Slack mrkdwn: *bold*, _italic_, bullet "•". Keep every line short.',
  '',
  'Produce these sections IN THIS ORDER, nothing extra:',
  '1) Bold title line: 🏆 WC2026 — <schedule weekday + short date e.g. Mon 15 Jun> • <matchCount> matches • times BDT',
  '2) If recentResults is non-empty, ONE italic line: _Last: CODE x-y CODE • CODE x-y CODE_ (FIFA codes + score).',
  '3) *⚽ Fixtures* then, per match in matches, TWO short lines: line one "• <bd_time> — <HOME_CODE> v <AWAY_CODE> (<Grp>)"; line two indented "    <stadium>, <city> • <kickoff_us_local>". Use FIFA codes. If matches is empty, write "• No matches — next up:" then the next few upcomingMatches the same way.',
  '4) *🔮 Win % (H/D/A est.)* then ONE line per match: "• <HOME_CODE> v <AWAY_CODE> — H/D/A" as plain numbers, e.g. "• NED v JPN — 55/25/20" (each set sums about 100).',
  '5) *⭐ Key players* then ONE line per team in matches: "• CODE: Player (Club), Player (Club)" — max 2 stars each, only when confident; skip a team if unsure.',
  '6) *📊 Standings (P/GD/Pts)* then, for each group appearing in matches: a "*Group X*" line, then one line per team "• Team — P/GD/Pts" sorted as given. If matches is empty, show all 12 groups this way.',
  '7) Final italic line: _Have a great matchday!_ ⚽',
  '',
  'Keep the whole message tight and skimmable on a phone. Absolutely no code blocks, no tables, no pipe alignment.',
  '',
  'DATA:',
  JSON.stringify(context)
].join('\n');

return [{ json: { scheduleDate: schedDate, scheduleHuman: schedHuman, prompt, context } }];

// Normalize the report text from an AI Agent node (output) OR the Claude Messages API (content[]).
const data = $input.first().json || {};
let report = '';
if (typeof data.output === 'string') {
  report = data.output.trim();                       // n8n AI Agent / LangChain node
} else if (typeof data.text === 'string') {
  report = data.text.trim();                          // Basic LLM Chain node
} else if (Array.isArray(data.content)) {
  report = data.content.filter(b => b.type === 'text').map(b => b.text).join('\n').trim(); // raw Claude API
} else if (data.message && typeof data.message.content === 'string') {
  report = data.message.content.trim();
}
if (!report) {
  report = '⚠️ No World Cup briefing was generated today. Check the AI Agent output and upstream feeds.';
}
return [{ json: { report } }];
